from claudescycles.verify import verify_decomposition

def construct_with_a(m,a):
    n=m*m*m
    dirs=[bytearray(n),bytearray(n),bytearray(n)]
    majority0_rows=set(range(2,2+a))
    for i in range(m):
        for j in range(m):
            v=(i+j)%m
            for k in range(m):
                w=(v+k)%m
                idx=i*m*m+j*m+k
                if w==0:
                    dirs[0][idx]=2
                    dirs[2][idx]=0 if v==0 else 1
                    dirs[1][idx]=1 if v==0 else 0
                elif w==1:
                    dirs[1][idx]=2
                    dirs[2][idx]=0 if v==0 else 1
                    dirs[0][idx]=1 if v==0 else 0
                else:
                    dirs[2][idx]=2
                    if w in majority0_rows:
                        dirs[0][idx]=1 if v==0 else 0
                        dirs[1][idx]=0 if v==0 else 1
                    else:
                        dirs[1][idx]=1 if v==0 else 0
                        dirs[0][idx]=0 if v==0 else 1
    return dirs

cases=[(9,0),(9,2),(6,0)]
for m,a in cases:
    r=verify_decomposition(m,construct_with_a(m,a))
    print({'m':m,'A':a,'ok':r.ok,'error':r.error})
    if not r.ok:
        for cc in r.cycle_checks:
            if not cc.ok:
                print('  bad cycle',cc.cycle_index,cc.error)
                break
